"use client";

import { Accordion as AccordionRoot, type AccordionProps, type AccordionSingleProps, type AccordionMultipleProps } from "./accordion";
import { AccordionHeader, type AccordionHeaderProps } from "./accordion-header";
import { AccordionItem, type AccordionItemProps } from "./accordion-item";
import { AccordionTrigger, type AccordionTriggerProps } from "./accordion-trigger";
import { AccordionContent, type AccordionContentProps } from "./accordion-content";

const Accordion = Object.assign(AccordionRoot, {
  Header: AccordionHeader,
  Item: AccordionItem,
  Trigger: AccordionTrigger,
  Content: AccordionContent,
});

export { Accordion, type AccordionProps, type AccordionSingleProps, type AccordionMultipleProps };
export { AccordionHeader, type AccordionHeaderProps };
export { AccordionItem, type AccordionItemProps };
export { AccordionTrigger, type AccordionTriggerProps };
export { AccordionContent, type AccordionContentProps };

"use client";

import {
  type KeyboardEvent as ReactKeyboardEvent,
  type ReactNode,
  type Ref,
  useMemo,
  useRef,
} from "react";
import { getNavigationItems } from "@/hooks/utils/navigation-items";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { AccordionContext } from "./accordion-context";
import { useAccordionState } from "./use-accordion-state";

const ACCORDION_ROOT_ATTRIBUTE = "data-diffgazer-accordion-root";

export interface AccordionSingleProps {
  type?: "single";
  value?: string;
  onChange?: (value: string | undefined) => void;
  defaultValue?: string;
  collapsible?: boolean;
  children: ReactNode;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

export interface AccordionMultipleProps {
  type: "multiple";
  value?: string[];
  onChange?: (value: string[]) => void;
  defaultValue?: string[];
  children: ReactNode;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
}

export type AccordionProps = AccordionSingleProps | AccordionMultipleProps;

function getNavigableTriggers(container: HTMLElement | null): HTMLElement[] {
  // Use skipDisabled: false because aria-disabled non-collapsible triggers
  // remain in the roving tab order per APG. Filter explicit HTML/data-disabled
  // ourselves.
  return getNavigationItems(container, {
    type: "button",
    skipDisabled: false,
    ownerSelector: `[${ACCORDION_ROOT_ATTRIBUTE}]`,
  }).filter((trigger) => {
    const View = trigger.ownerDocument.defaultView;
    if (trigger.dataset.disabled !== undefined) return false;
    if (View && trigger instanceof View.HTMLButtonElement && trigger.disabled) return false;
    return true;
  });
}

function containsActiveElement(el: HTMLElement): boolean {
  const activeElement = el.ownerDocument.activeElement;
  const View = el.ownerDocument.defaultView;
  return Boolean(View && activeElement instanceof View.HTMLElement && el.contains(activeElement));
}

function AccordionRoot(props: AccordionProps) {
  const { ref, onKeyDown: externalOnKeyDown } = props;
  const { openValues, onToggle, collapsible } = useAccordionState(props);
  const containerRef = useRef<HTMLDivElement>(null);

  const focusTrigger = (index: number) => {
    const triggers = getNavigableTriggers(containerRef.current);
    const trigger = triggers[index];
    if (!trigger) return;

    trigger.scrollIntoView?.({ block: "nearest" });
    trigger.focus();
  };

  const handleKeyDown = (e: ReactKeyboardEvent) => {
    externalOnKeyDown?.(e);
    if (e.defaultPrevented) return;

    const triggers = getNavigableTriggers(containerRef.current);
    if (triggers.length === 0) return;

    const currentIndex = triggers.findIndex(containsActiveElement);
    if (currentIndex < 0) return;

    switch (e.key) {
      case "ArrowUp":
        focusTrigger(currentIndex <= 0 ? triggers.length - 1 : currentIndex - 1);
        e.preventDefault();
        break;
      case "ArrowDown":
        focusTrigger(currentIndex >= triggers.length - 1 ? 0 : currentIndex + 1);
        e.preventDefault();
        break;
      case "Home":
        focusTrigger(0);
        e.preventDefault();
        break;
      case "End":
        focusTrigger(triggers.length - 1);
        e.preventDefault();
        break;
    }
  };

  const contextValue = useMemo(
    () => ({ value: openValues, onToggle, collapsible }),
    [openValues, onToggle, collapsible],
  );

  return (
    <AccordionContext value={contextValue}>
      <div
        ref={composeRefs(containerRef, ref)}
        role="group"
        className={cn("divide-y divide-border", props.className)}
        onKeyDown={handleKeyDown}
        {...{ [ACCORDION_ROOT_ATTRIBUTE]: "" }}
      >
        {props.children}
      </div>
    </AccordionContext>
  );
}

export { AccordionRoot as Accordion };

"use client";

import { createContext, useContext } from "react";

export interface AccordionContextValue {
  value: string[];
  onToggle: (itemValue: string) => void;
  collapsible: boolean;
}

export const AccordionContext = createContext<AccordionContextValue | undefined>(undefined);

export function useAccordionContext() {
  const context = useContext(AccordionContext);
  if (!context) {
    throw new Error("Accordion compound components must be used within Accordion");
  }
  return context;
}

export interface AccordionItemContextValue {
  value: string;
  isOpen: boolean;
  disabled: boolean;
  triggerId: string;
  contentId: string;
}

export const AccordionItemContext = createContext<AccordionItemContextValue | undefined>(undefined);

export function useAccordionItemContext() {
  const context = useContext(AccordionItemContext);
  if (!context) {
    throw new Error("AccordionTrigger/AccordionContent must be used within AccordionItem");
  }
  return context;
}

"use client";

import { type ReactNode } from "react";
import { cn } from "@/lib/utils";

export interface AccordionHeaderProps {
  as?: "h2" | "h3" | "h4" | "h5" | "h6";
  children: ReactNode;
  className?: string;
}

export function AccordionHeader({ as: Tag = "h3", children, className }: AccordionHeaderProps) {
  return <Tag className={cn("m-0 font-normal", className)}>{children}</Tag>;
}

"use client";

import { useId, useMemo, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAccordionContext, AccordionItemContext } from "./accordion-context";

export interface AccordionItemProps {
  value: string;
  disabled?: boolean;
  children: ReactNode;
  className?: string;
}

export function AccordionItem({ value, disabled = false, children, className }: AccordionItemProps) {
  const { value: openValues } = useAccordionContext();
  const isOpen = openValues.includes(value);
  const itemId = useId();
  const triggerId = `${itemId}-trigger`;
  const contentId = `${itemId}-content`;

  const contextValue = useMemo(() => ({ value, isOpen, disabled, triggerId, contentId }), [value, isOpen, disabled, triggerId, contentId]);

  return (
    <AccordionItemContext value={contextValue}>
      <div className={cn("py-2", className)} data-state={isOpen ? "open" : "closed"} data-disabled={disabled || undefined}>
        {children}
      </div>
    </AccordionItemContext>
  );
}

"use client";

import { type ComponentPropsWithRef, type MouseEvent, type ReactNode } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useAccordionContext, useAccordionItemContext } from "./accordion-context";

const triggerVariants = cva(
  "flex w-full items-center gap-2 font-mono text-muted-foreground hover:text-foreground transition-colors cursor-pointer disabled:cursor-not-allowed disabled:hover:text-muted-foreground focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
  {
    variants: {
      variant: {
        default: "text-sm",
        source: "text-xs mb-2",
      },
      disabled: {
        true: "opacity-50 cursor-not-allowed hover:text-muted-foreground",
        false: "",
      },
    },
    defaultVariants: { variant: "default", disabled: false },
  }
);

export interface AccordionTriggerProps
  extends Omit<ComponentPropsWithRef<"button">, "children">,
    Omit<VariantProps<typeof triggerVariants>, "disabled"> {
  children: ReactNode;
  /** Custom handle element. Defaults to an animated Chevron. Pass `null` to hide. */
  handle?: ReactNode | null;
}

export function AccordionTrigger({
  children,
  className,
  variant,
  handle,
  disabled: triggerDisabled,
  ref,
  onClick,
  ...props
}: AccordionTriggerProps) {
  const { onToggle, collapsible } = useAccordionContext();
  const { value, isOpen, disabled, triggerId, contentId } = useAccordionItemContext();

  const isAriaDisabled = !collapsible && isOpen;
  const isDisabled = disabled || !!triggerDisabled;
  const resolvedHandle = handle === undefined ? <Chevron open={isOpen} size="sm" /> : handle;
  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    onClick?.(event);
    if (event.defaultPrevented) return;

    if (isDisabled || isAriaDisabled) {
      event.preventDefault();
      return;
    }

    onToggle(value);
  };

  return (
    <button
      {...props}
      ref={ref}
      type="button"
      id={triggerId}
      data-value={value}
      data-diffgazer-navigation-item="button"
      data-disabled={isDisabled ? "" : undefined}
      onClick={handleClick}
      disabled={isDisabled}
      aria-disabled={isAriaDisabled || disabled || undefined}
      aria-expanded={isOpen}
      aria-controls={contentId}
      className={cn(triggerVariants({ variant, disabled: isDisabled || isAriaDisabled }), className)}
    >
      {resolvedHandle}
      {children}
    </button>
  );
}

"use client";

import { type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useAccordionItemContext } from "./accordion-context";

export interface AccordionContentProps {
  children: ReactNode;
  className?: string;
  region?: boolean;
}

export function AccordionContent({ children, className, region = false }: AccordionContentProps) {
  const { isOpen, triggerId, contentId } = useAccordionItemContext();
  const exposesRegion = region && isOpen;

  return (
    <div
      className={cn(
        "grid transition-[grid-template-rows] duration-200 ease-out motion-reduce:transition-none",
        isOpen ? "grid-rows-[1fr]" : "grid-rows-[0fr]"
      )}
      aria-hidden={!isOpen || undefined}
      inert={!isOpen || undefined}
    >
      <div
        className={cn("overflow-hidden min-h-0 pt-2", className)}
        role={exposesRegion ? "region" : undefined}
        id={contentId}
        aria-labelledby={exposesRegion ? triggerId : undefined}
      >
        {children}
      </div>
    </div>
  );
}

"use client";

import { useCallback } from "react";
import {
  useControllableState,
  type UseControllableStateOptions,
} from "@/hooks/use-controllable-state";
import type { AccordionProps } from "./accordion";

function normalizeStateOptions(
  props: AccordionProps,
): UseControllableStateOptions<string[]> {
  if (props.type === "multiple") {
    return {
      value: props.value,
      controlled: "value" in props,
      defaultValue: props.defaultValue ?? [],
      onChange: props.onChange,
    };
  }
  return {
    value: "value" in props ? (props.value === undefined ? [] : [props.value]) : undefined,
    controlled: "value" in props,
    defaultValue: props.defaultValue !== undefined ? [props.defaultValue] : [],
    onChange: props.onChange ? (v: string[]) => props.onChange?.(v[0]) : undefined,
  };
}

function toggleSingle(
  prev: string[],
  value: string,
  collapsible: boolean,
): string[] {
  return prev.includes(value) ? (collapsible ? [] : prev) : [value];
}

function toggleMultiple(prev: string[], value: string): string[] {
  return prev.includes(value)
    ? prev.filter((v) => v !== value)
    : [...prev, value];
}

export function useAccordionState(props: AccordionProps) {
  const isSingle = props.type !== "multiple";
  const collapsible = props.type !== "multiple"
    ? (props.collapsible ?? true)
    : true;

  const [openValues, setOpenValues] = useControllableState(
    normalizeStateOptions(props),
  );

  const onToggle = useCallback((itemValue: string) => {
    setOpenValues((prev) =>
      isSingle
        ? toggleSingle(prev, itemValue, collapsible)
        : toggleMultiple(prev, itemValue),
    );
  }, [collapsible, isSingle, setOpenValues]);

  return { openValues, onToggle, collapsible };
}
